# Inference-healed code review reward

def inference_healed_reward(patch):
    subscores = {
        'correctness': test_critic.score(patch),      # Tests pass?
        'style': linter_critic.score(patch),          # Linter warnings?
        'performance': perf_critic.score(patch),      # Benchmark regression?
        'security': security_critic.score(patch),     # Static analysis issues?
    }

    weights = {
        'correctness': 0.4,
        'style': 0.2,
        'performance': 0.2,
        'security': 0.2
    }

    final_score = sum(weights[k] * subscores[k] for k in subscores)

    # CoT reasoning for explainability
    comments = generate_cot_explanation(patch, subscores)

    return {
        'score': final_score,
        'subscores': subscores,
        'comments': comments  # e.g., "Performance regression due to O(n²) loop"
    }

# Example output:
# {'correctness': 1.0, 'style': 0.8, 'performance': 0.4, 'security': 0.6,
